        min: Optional['types.BudgetMinAggregateInput'] = None,
        max: Optional['types.BudgetMaxAggregateInput'] = None,
        having: Optional['types.BudgetScalarWhereWithAggregatesInput'] = None,
        count: Optional[Union[bool, 'types.BudgetCountAggregateInput']] = None,
        order: Optional[Union[Mapping['types.BudgetScalarFieldKeys', 'types.SortOrder'], List[Mapping['types.BudgetScalarFieldKeys', 'types.SortOrder']]]] = None,
